<template >
    <div class = "notifications " >
        <button v-show = "view === 'minimized'"
                @click = "view = 'full'"
                class = "notifications__button"
                :class = "hasNew ? 'new' : ''"
                type = "button" >
            <svg viewBox = "0 0 24 24" fill = "none" xmlns = "http://www.w3.org/2000/svg" >
                <path d = "M18 8C18 6.4087 17.3679 4.88258 16.2426 3.75736C15.1174 2.63214 13.5913 2 12 2C10.4087 2 8.88258 2.63214 7.75736 3.75736C6.63214 4.88258 6 6.4087 6 8C6 15 3 17 3 17H21C21 17 18 15 18 8Z"
                      stroke = "#8C8C8C" stroke-width = "2" stroke-linecap = "round" stroke-linejoin = "round" />
                <path d = "M13.73 21C13.5542 21.3031 13.3019 21.5547 12.9982 21.7295C12.6946 21.9044 12.3504 21.9965 12 21.9965C11.6496 21.9965 11.3054 21.9044 11.0018 21.7295C10.6982 21.5547 10.4458 21.3031 10.27 21"
                      stroke = "#8C8C8C" stroke-width = "2" stroke-linecap = "round" stroke-linejoin = "round" />
            </svg >
        </button >
        <div v-show = "view !== 'minimized'"
             class = "notifications__block" >
            <button class = "notifications-ttl btn-reset summ"
                    @click = "view = 'minimized'"
                    type = "button" >Уведомления
            </button >
            <ul class = "notifications-list" >
                <li v-for = "item in notificationsList"
                    :key = "item.id"
                    :class = "item.isNew ? 'new': ''"
                    class = "notifications-list__itm"
                    :data-id = "item.id"
                    @click = "item.isNew = false" >
                    <strong class = "notifications-itm-t" >{{item.topic}}</strong >
                    <p class = "notifications-itm-p" >{{item.text}}</p >
                    <span class = "notifications-itm-d" >{{item.date}}</span >
                </li >
            </ul >
        </div >
    </div >
</template >

<script >
  import axios from "axios";

  export default {
    name: "notifications",
    data() {
      return {
        view: "minimized",
        notificationsList: [],
      };
    },
    computed: {
      hasNew: function () {
        let newMessages = this.notificationsList.filter(function (i) {
          return i.isNew == true;
        });
        return newMessages.length > 0;
      },
    },
    methods: {
      getMessages: function () {
        let vm = this;
        axios.get(
            "/json/notifications.json",
            {
              headers: {
                "Content-Type": "application/json",
              },
            },
        ).then(response => {
          if (response.status == 200) {
            response.data.map(item => {
              vm.notificationsList.push(item);
            });
          }
        }).catch(error => console.error(error));
      },
    },
    mounted() {
      this.getMessages();
    },
  };
</script >

<style scoped >
    @import "../includes/styles/_buttons.css";

    .notifications .notifications__button {
        position: fixed;
        right: 0;
        top: 136px;
        display: block;
        width: 50px;
        height: 50px;
        padding: 13px;
        background: #FFFFFF;
        border: none;
        border-radius: 10px 0 0 10px;
        box-shadow: 0 0 7px rgba(0, 0, 0, 0.05);
        }

    .notifications .notifications__button::before {
        content: '';
        position: absolute;
        top: 12px;
        right: 13px;
        display: block;
        width: 10px;
        height: 10px;
        border-radius: 50%;
        background: #F55F44;
        opacity: 0;
        transform: scale(.2);
        transition: all .2s linear;
        }

    .notifications .notifications__button.new::before {
        opacity: 1;
        transform: scale(1);
        }

    .notifications .notifications__button svg {
        display: block;
        width: 100%;
        height: 100%;
        }

    .notifications .notifications__block {
        position: fixed;
        top: 136px;
        right: 15px;
        display: flex;
        flex-direction: column;
        width: 300px;
        max-width: calc(100vw - 15px * 2);
        max-height: 450px;
        padding: 16px 11px;
        background: #FFFFFF;
        box-shadow: 0 3px 7px rgba(0, 0, 0, 0.1);
        border-radius: 10px;
        }

    .notifications-ttl {
        margin-bottom: 15px;
        color: #454242;
        text-align: center;
        }

    .notifications-list {
        overflow-x: hidden;
        overflow-y: auto;
        }

    .notifications-list .notifications-list__itm {
        padding: 5px 9px;
        border-radius: 6px;
        color: #454242;
        transition: all .2s linear;
        }

    .notifications-list .notifications-list__itm.new {
        background-color: #F8F8F8;
        }

    .notifications-list .notifications-list__itm:not(:last-child) {margin-bottom: 4px;}

    .notifications-itm-t {margin-bottom: 7px;}

    .notifications-itm-p {margin-bottom: 7px;}

    .notifications-itm-d {color: #8c8c8c;}
</style >